function calcPathLength(path) {
  var length = 0;
  var numPoints = path.length;
  for (var i = 1; i < numPoints; i++) {
    length += lengthTo(path[i - 1], path[i]);
  }
  return length;
}
function lengthTo(point1, point2) {
  return Math.sqrt(Math.pow(point2[0] - point1[0], 2) + Math.pow(point2[1] - point1[1], 2));
}
var controlLayer = thisComp.layer("CTRL");
var selectedPathLayer = controlLayer.effect("Distribute Along the Path")("Distribution Path Layer ");
var pathProperty = selectedPathLayer.mask("Mask 1").maskPath;
var time = time;
var path = pathProperty.points(time);
var pathLength = calcPathLength(path);
var randomRotation = controlLayer.effect("Distribute Along the Path")("Randomize Rotation");
var offsetRotation = controlLayer.effect("Distribute Along the Path")("Rotation Offset");
var startIndex = controlLayer.effect("Distribute Along the Path")("First Layer Index");
var endIndex = controlLayer.effect("Distribute Along the Path")("Last Layer Index");
var endOffset = controlLayer.effect("Distribute Along the Path")("End Distribution Offset");
var startOffset = controlLayer.effect("Distribute Along the Path")("Start Distribution Offset");
var effectivePathLength = pathLength - endOffset - startOffset;
var myIndex = index - startIndex;
var t = startOffset + myIndex / (endIndex - startIndex) * effectivePathLength;
var pos = pathProperty.pointOnPath(t / pathLength, time);
var tangent = pathProperty.normalOnPath(t / pathLength, time);
var angle = Math.atan2(tangent[1], tangent[0]) * 180 / Math.PI;
var rotation = angle + 90 + offsetRotation + randomRotation * (Math.random() - 0.5) * 2;
if (thisProperty.name === "Position") {
  pos;
} else if (thisProperty.name === "Rotation") {
  rotation;
}

